class Solution {
public:
    long long minimumSteps(string s) {
        long long count = 0, totalSwaps = 0;
        for (int i = s.size() - 1; i >= 0; --i) {
            if (s[i] == '1') {
                ++count;
            } else {
                totalSwaps += count;
            }
        }
        return totalSwaps;
    }
};
